+func captureDoltStopOutput(t *testing.T) string {
+	t.Helper()
+	oldStdout := os.Stdout
+	oldStderr := os.Stderr
+	r, w, _ := os.Pipe()
+	os.Stdout = w
+	os.Stderr = w
+
+	defer func() {
+		os.Stdout = oldStdout
+		os.Stderr = oldStderr
+		if rec := recover(); rec != nil {
+			// Ignore panics from os.Exit
+		}
+	}()
+
+	stopDoltServer()
+
+	w.Close()
+	var buf bytes.Buffer
+	io.Copy(&buf, r)
+
+	return buf.String()
+}
